/**
 * Token-efficiency fixture corpus (#1256).
 *
 * The corpus is 5 archetypes × 10 instances = 50 fixtures, generated by
 * `scripts/bench/generate-token-fixtures.mjs` and committed to disk under
 * this directory. See `RUBRIC.md` for field categories + matching semantics
 * and `README.md` for the per-archetype field list.
 *
 * This file is the public surface other modules import from
 * `./fixtures/token-efficiency/corpus`. The actual filesystem read happens in
 * `loader.ts` — kept separate so unit tests can poke the loader directly.
 */

import {
  FIXTURE_ARCHETYPES,
  FixtureArchetype,
  TokenEfficiencyFixture,
  deterministicExtract,
  loadTokenEfficiencyCorpus,
} from './loader';

export type { FixtureArchetype, TokenEfficiencyFixture };
export { FIXTURE_ARCHETYPES, deterministicExtract };

/**
 * The full fixture corpus, eagerly loaded at module-init time so callers can
 * treat it as a constant array. Matches the previous inline-corpus contract.
 */
export const TOKEN_EFFICIENCY_CORPUS: readonly TokenEfficiencyFixture[] =
  Object.freeze(loadTokenEfficiencyCorpus());
